+        // DP: cost[i][j] = min cost to multiply arrays i..=j
+        // split[i][j] = optimal split point k such that (i..=k) * (k+1..=j)
+        let mut cost = vec![vec![0u64; n]; n];
+        let mut split = vec![vec![0usize; n]; n];
+
+        // chain length l from 2 to n
