+                                .saturating_mul(dims[k + 1] as u64)
+                                .saturating_mul(dims[j + 1] as u64),
+                        );
+                    if c < cost[i][j] {
+                        cost[i][j] = c;
+                        split[i][j] = k;
+                    }
+                }
+            }
